  return [...cells].sort((a, b) => a[1] - b[1] || a[0] - b[0]);
}

describe("Game of Life - nextGeneration", () => {
  it.todo("should return empty grid for empty input -- [] -> []");
  it.todo("should kill a single cell with 0 neighbors (underpopulation) -- [(0,0)] -> []");
  it.todo("should kill two adjacent cells each with 1 neighbor (underpopulation) -- [(0,0),(1,0)] -> []");
  it.todo("should kill center cell with 4 neighbors (overpopulation) and outer cells with 1 neighbor (underpopulation) -- cross shape -> []");
  it.todo("should keep three L-shaped cells alive with 2 neighbors each, and reproduce dead cell with 3 neighbors -- [(0,0),(0,1),(1,0)] -> [(0,0),(0,1),(1,0),(1,1)]");
  it.todo("should keep 2x2 block unchanged (still life) -- [(0,0),(0,1),(1,0),(1,1)] -> same");
  it.todo("should transform vertical blinker to horizontal blinker (oscillator) -- [(0,0),(0,1),(0,2)] -> [(-1,1),(0,1),(1,1)]");
});

export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  throw new Error("not implemented");
}

